import {
  forwardRef,
  useCallback,
  useEffect,
  useId,
  useRef,
  useState,
} from 'react';
import { getDefaultErrorMsg } from '@arvo/utils';
import { useTooltip } from '../../hooks/useTooltip';
import ArvoIconButton from '../IconButton/IconButton';

interface MultiLineConfig {
  enabled: boolean;
  expandRows: boolean;
  maxRows: number;
  delimiter: string;
}

export interface ArvoSearchProps {
  variant?: 'filter' | 'find';
  value?: string;
  defaultValue?: string;
  placeholder?: string;
  isDisabled?: boolean;
  isInvalid?: boolean;
  errorMsg?: string;
  errorDisplay?: 'inline' | 'tooltip' | 'none';
  isClearable?: boolean;
  shortcut?: string;
  counter?: { current: number; total: number } | null;
  searchMode?: 'input' | 'submit';
  minChars?: number;
  isMultiLine?:
    | boolean
    | {
        enabled: boolean;
        expandRows?: boolean;
        maxRows?: number;
        delimiter?: string;
      };
  isLoading?: boolean;
  width?: string;
  isFullWidth?: boolean;
  onSearch?: (value: string, values?: string[]) => void;
  onInput?: React.FormEventHandler<HTMLInputElement | HTMLTextAreaElement>;
  onChange?: (value: string) => void;
  onClear?: () => void;
  onFocus?: React.FocusEventHandler<HTMLInputElement | HTMLTextAreaElement>;
  onBlur?: React.FocusEventHandler<HTMLInputElement | HTMLTextAreaElement>;
  onNext?: () => void;
  onPrevious?: () => void;
  className?: string;
  'aria-label'?: string;
}

const ML_DEFAULTS: MultiLineConfig = {
  enabled: true,
  expandRows: true,
  maxRows: 3,
  delimiter: ',',
};

const LINE_HEIGHT = 20;
const TEXTAREA_PAD_Y = 12;

function normalizeMultiLine(
  prop: ArvoSearchProps['isMultiLine']
): MultiLineConfig | null {
  if (!prop) return null;
  if (prop === true) return { ...ML_DEFAULTS };
  if (!prop.enabled) return null;
  return {
    enabled: true,
    expandRows: prop.expandRows ?? ML_DEFAULTS.expandRows,
    maxRows: prop.maxRows ?? ML_DEFAULTS.maxRows,
    delimiter: prop.delimiter ?? ML_DEFAULTS.delimiter,
  };
}

function parseShortcut(shortcut: string) {
  const parts = shortcut.split('+').map((p) => p.trim().toLowerCase());
  const key = parts.pop()!;
  const isMac =
    typeof navigator !== 'undefined' &&
    /mac|iphone|ipad/i.test(navigator.platform);
  const hasCtrl = parts.includes('ctrl') || parts.includes('cmd');
  return {
    key,
    ctrl: hasCtrl && !isMac,
    alt: parts.includes('alt'),
    shift: parts.includes('shift'),
    meta: (hasCtrl && isMac) || parts.includes('meta'),
  };
}

function parseValues(value: string, delimiter: string): string[] {
  return value
    .split('\n')
    .flatMap((line) => line.split(delimiter))
    .map((s) => s.trim())
    .filter(Boolean);
}

const ArvoSearch = forwardRef<HTMLDivElement, ArvoSearchProps>(
  function ArvoSearch(
    {
      variant = 'filter',
      value,
      defaultValue = '',
      placeholder = 'Search',
      isDisabled = false,
      isInvalid = false,
      errorMsg,
      errorDisplay = 'inline',
      isClearable = true,
      shortcut,
      counter = null,
      searchMode = 'input',
      minChars = 0,
      isMultiLine: multiLineProp,
      isLoading = false,
      width,
      isFullWidth = false,
      onSearch,
      onInput,
      onChange,
      onClear,
      onFocus,
      onBlur,
      onNext,
      onPrevious,
      className,
      'aria-label': ariaLabel = 'Search',
    },
    ref
  ) {
    const uid = useId();
    const errorId = `arvo-search-err-${uid}`;
    const inputRef = useRef<HTMLInputElement | HTMLTextAreaElement | null>(null);
    const fieldRef = useRef<HTMLDivElement>(null);
    const actionsRef = useRef<HTMLDivElement>(null);
    const errIcoRef = useRef<HTMLSpanElement>(null);
    const valueOnFocusRef = useRef(defaultValue);

    const isControlled = value !== undefined;
    const [internalValue, setInternalValue] = useState(defaultValue);
    const currentValue = isControlled ? value : internalValue;
    const hasValue = currentValue.length > 0;

    const [isFocusWithin, setIsFocusWithin] = useState(false);
    const [isHovered, setIsHovered] = useState(false);

    const mlConfig =
      variant === 'filter' ? normalizeMultiLine(multiLineProp) : null;
    const isMultiLine = !!mlConfig;
    const effectiveClearable = isClearable && !isMultiLine;

    const errorMessage = errorMsg ?? getDefaultErrorMsg();
    const showTooltipIcon = isInvalid && errorDisplay === 'tooltip';
    const showInlineAlert = isInvalid && errorDisplay === 'inline';
    useTooltip({
      triggerRef: errIcoRef,
      tooltip: showTooltipIcon ? errorMessage : undefined,
    });

    const isTouchRef = useRef(
      typeof document !== 'undefined' &&
        !document.documentElement.classList.contains('no-touch')
    );

    // --- Classes ---

    const classes = [
      'arvo-search',
      `arvo-search--${variant}`,
      isMultiLine && 'arvo-search--multi-line',
      isFullWidth && 'arvo-search--full-width',
      hasValue && 'has-value',
      isInvalid && 'has-error',
      showTooltipIcon && 'error-tooltip',
      isDisabled && 'is-disabled',
      isLoading && 'loading',
      className,
    ]
      .filter(Boolean)
      .join(' ');

    // --- Dynamic padding ---

    const updatePadding = useCallback(() => {
      if (!actionsRef.current || !fieldRef.current) return;
      const w = actionsRef.current.offsetWidth;
      const pad = w > 0 ? w + 4 : 4;
      fieldRef.current.style.setProperty('--arvo-search-pad-r', `${pad}px`);
    }, []);

    useEffect(() => {
      updatePadding();
    });

    useEffect(() => {
      const el = actionsRef.current;
      if (!el) return;
      const obs = new ResizeObserver(updatePadding);
      obs.observe(el);
      return () => obs.disconnect();
    }, [updatePadding]);

    // --- Textarea auto-resize ---

    const autoResize = useCallback(() => {
      const el = inputRef.current as HTMLTextAreaElement | null;
      if (!el || !mlConfig) return;
      el.style.height = 'auto';
      const max = mlConfig.maxRows * LINE_HEIGHT + TEXTAREA_PAD_Y;
      if (el.scrollHeight > max) {
        el.style.height = `${max}px`;
        el.style.overflowY = 'auto';
      } else {
        el.style.height = `${el.scrollHeight}px`;
        el.style.overflowY = 'hidden';
      }
    }, [mlConfig]);

    useEffect(() => {
      if (isMultiLine) autoResize();
    }, [currentValue, isMultiLine, autoResize]);

    // --- Blur on loading/disabled ---

    useEffect(() => {
      if (
        (isLoading || isDisabled) &&
        document.activeElement === inputRef.current
      ) {
        inputRef.current?.blur();
      }
    }, [isLoading, isDisabled]);

    // --- Shortcut global listener ---

    useEffect(() => {
      if (!shortcut || isDisabled || isLoading) return;
      const combo = parseShortcut(shortcut);
      const handler = (e: KeyboardEvent) => {
        const t = e.target as HTMLElement;
        if (
          t !== inputRef.current &&
          (t.tagName === 'INPUT' ||
            t.tagName === 'TEXTAREA' ||
            t.tagName === 'SELECT' ||
            t.isContentEditable)
        )
          return;
        if (document.activeElement === inputRef.current) return;
        if (
          e.key.toLowerCase() === combo.key &&
          e.ctrlKey === combo.ctrl &&
          e.altKey === combo.alt &&
          e.shiftKey === combo.shift &&
          e.metaKey === combo.meta
        ) {
          e.preventDefault();
          e.stopPropagation();
          inputRef.current?.focus();
          inputRef.current?.select();
        }
      };
      document.addEventListener('keydown', handler, true);
      return () => document.removeEventListener('keydown', handler, true);
    }, [shortcut, isDisabled, isLoading]);

    // --- Separator visibility ---

    const clearVisible =
      effectiveClearable &&
      hasValue &&
      !isDisabled &&
      !isLoading &&
      (isFocusWithin || isHovered || isTouchRef.current);
    const counterVisible = !!counter && hasValue && !isDisabled;
    const shortcutVisible = !!shortcut && !hasValue && !isFocusWithin;
    const sep1 = clearVisible && (counterVisible || shortcutVisible);
    const sep2 = variant === 'find' && !isDisabled && !isLoading;

    // --- Nav state ---

    const navDisabled =
      isDisabled || isLoading || (counter != null && counter.total === 0);

    // --- Search trigger ---

    function fireSearch(val: string) {
      if (!onSearch) return;
      if (mlConfig) {
        onSearch(val, parseValues(val, mlConfig.delimiter));
      } else {
        onSearch(val);
      }
    }

    // --- Handlers ---

    function handleInputEvent(
      e: React.FormEvent<HTMLInputElement | HTMLTextAreaElement>
    ) {
      if (isDisabled || isLoading) {
        e.preventDefault();
        return;
      }
      onInput?.(e);
    }

    function handleValueChange(
      e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
    ) {
      if (isDisabled || isLoading) {
        e.preventDefault();
        return;
      }
      const v = e.target.value;
      if (!isControlled) setInternalValue(v);

      if (searchMode === 'input' && v.length >= minChars) {
        fireSearch(v);
      }
    }

    function handleFocus(
      e: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>
    ) {
      valueOnFocusRef.current = currentValue;
      onFocus?.(e);
    }

    function handleBlur(
      e: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>
    ) {
      if (currentValue !== valueOnFocusRef.current) {
        onChange?.(currentValue);
      }
      onBlur?.(e);
    }

    function handleKeyDown(
      e: React.KeyboardEvent<HTMLInputElement | HTMLTextAreaElement>
    ) {
      if (isDisabled || isLoading) {
        e.preventDefault();
        e.stopPropagation();
        return;
      }

      if (e.key === 'Escape') {
        if (effectiveClearable && hasValue) {
          doClear();
        } else {
          (e.target as HTMLElement).blur();
        }
        return;
      }

      if (e.key === 'Enter') {
        if (variant === 'find') {
          e.preventDefault();
          if (e.shiftKey) onPrevious?.();
          else onNext?.();
          return;
        }

        if (isMultiLine && e.shiftKey) {
          requestAnimationFrame(autoResize);
          return;
        }

        e.preventDefault();
        fireSearch(currentValue);
      }
    }

    function handlePaste() {
      if (isMultiLine) requestAnimationFrame(autoResize);
    }

    function doClear() {
      if (!isControlled) setInternalValue('');
      onClear?.();
      inputRef.current?.focus();
      if (searchMode === 'input') {
        fireSearch('');
      }
    }

    // --- Focus-within / hover tracking (for separator logic) ---

    function handleRootFocusCapture() {
      setIsFocusWithin(true);
    }

    function handleRootBlurCapture(e: React.FocusEvent<HTMLDivElement>) {
      if (!e.currentTarget.contains(e.relatedTarget as Node)) {
        setIsFocusWithin(false);
      }
    }

    // --- Shared input attributes ---

    const inputAttrs = {
      className: 'arvo-search__input',
      value: currentValue,
      placeholder,
      disabled: isDisabled,
      'aria-label': ariaLabel,
      'aria-invalid': (isInvalid || undefined) as true | undefined,
      'aria-describedby': showInlineAlert ? errorId : undefined,
      onInput: handleInputEvent,
      onFocus: handleFocus,
      onBlur: handleBlur,
      onKeyDown: handleKeyDown,
      onPaste: handlePaste,
    };

    // --- Width style ---

    const rootStyle: React.CSSProperties | undefined = (() => {
      const effectiveWidth = isFullWidth ? '100%' : width;
      if (!effectiveWidth) return undefined;
      return { '--arvo-form-input-width': effectiveWidth } as React.CSSProperties;
    })();

    // --- Render ---

    return (
      <div
        ref={ref}
        className={classes}
        style={rootStyle}
        role="search"
        aria-busy={isLoading || undefined}
        aria-disabled={isDisabled || undefined}
        onFocusCapture={handleRootFocusCapture}
        onBlurCapture={handleRootBlurCapture}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
      >
        <div ref={fieldRef} className="arvo-search__field">
          <i
            className="arvo-search__ico o9con o9con-search"
            aria-hidden="true"
          />

          {isMultiLine ? (
            <textarea
              ref={inputRef as React.RefObject<HTMLTextAreaElement>}
              {...inputAttrs}
              rows={1}
              aria-multiline="true"
              onChange={
                handleValueChange as React.ChangeEventHandler<HTMLTextAreaElement>
              }
            />
          ) : (
            <input
              ref={inputRef as React.RefObject<HTMLInputElement>}
              {...inputAttrs}
              type="search"
              onChange={
                handleValueChange as React.ChangeEventHandler<HTMLInputElement>
              }
            />
          )}

          <div ref={actionsRef} className="arvo-search__actions">
            {effectiveClearable && hasValue && !isDisabled && !isLoading && (
              <ArvoIconButton
                size="sm"
                variant="tertiary"
                icon="close"
                tooltip="Clear"
                tabIndex={-1}
                onClick={doClear}
                className="arvo-search__clear"
              />
            )}

            {sep1 && (
              <span
                className="arvo-search__sep"
                style={{ display: 'block' }}
                aria-hidden="true"
              />
            )}

            {shortcut && (
              <span className="arvo-search__shortcut">{shortcut}</span>
            )}

            {counter && (
              <span className="arvo-search__counter" aria-live="polite">
                {counter.current}/{counter.total}
              </span>
            )}

            {variant === 'find' && (
              <>
                {sep2 && (
                  <span
                    className="arvo-search__sep"
                    style={{ display: 'block' }}
                    aria-hidden="true"
                  />
                )}
                <ArvoIconButton
                  size="sm"
                  variant="tertiary"
                  icon="angle-up"
                  tooltip="Previous match"
                  isDisabled={navDisabled}
                  onClick={onPrevious}
                  className="arvo-search__prev"
                />
                <ArvoIconButton
                  size="sm"
                  variant="tertiary"
                  icon="angle-down"
                  tooltip="Next match"
                  isDisabled={navDisabled}
                  onClick={onNext}
                  className="arvo-search__next"
                />
              </>
            )}

            {showTooltipIcon && (
              <span
                ref={errIcoRef}
                className="arvo-search__err-ico"
                role="img"
                aria-label={errorMessage}
              />
            )}
          </div>

          <div className="arvo-search__border" />
        </div>

        {showInlineAlert && (
          <div
            className="arvo-inline-alert arvo-inline-alert--error"
            id={errorId}
            role="alert"
          >
            <span className="arvo-inline-alert__ico" aria-hidden="true" />
            <span className="arvo-inline-alert__msg">{errorMessage}</span>
          </div>
        )}
      </div>
    );
  }
);

export default ArvoSearch;
